### Description

I have a form with different properties.

```ts
export interface Field {
  fieldName: string;
  fieldType?: string;
  fieldRequired?: boolean;
  fieldMaxSize?: number;
  fieldVisible?: boolean;
}

export interface FieldConfig {
  fields: Field[];
}

export interface Order {
  label: string;
  // ...
}

export interface ActivityType {
  label: string;
  fieldConfig: FieldConfig;
}

export function fieldConfigSchema<T>(fieldConfig: FieldConfig) {
  return schema<T>(path => {
    for (const field of fieldConfig.fields) {
      required(path[field.fieldName], { when: () => field.fieldRequired });
      hidden(path[field.fieldName], () => !field.fieldVisible);
      maxLength(path[field.fieldName], () => field.fieldMaxSize);
    }
  });
}

export interface FormModel {
  user: User;
  activityType: ActivityType;
  order: Order;
}
```

The form is defined as follows:

```ts
formModel = signal<FormModel>({
  user: null,
  activityType: null,
  order: null
});

form = form(this.formModel, path => {
  applyWhen(
    path.order,
    context => !!context.valueOf(path.activityType)?.fieldConfig,
    fieldConfigSchema(
      /* value of fieldConfig from activityType not available here */
    )
  );
});
```

The issue is that `fieldConfigSchema` needs access to the `fieldConfig`
coming from the selected `activityType`, but that value is only available
through the form context.

---

### Proposed solution

Allow building a schema dynamically based on the form context:

```ts
applyWhen(
  path.order,
  context => !!context.valueOf(path.activityType)?.fieldConfig,
  context =>
    fieldConfigSchema(
      context.valueOf(path.activityType).fieldConfig
    )
);
```

This would allow the schema to be constructed using runtime values from
the form context.

---

### Alternatives considered

```ts
export function fieldConfigSchema<T>(fieldConfig: Signal<FieldConfig>) {
  return schema<T>(path => {
    for (const field of fieldConfig().fields) {
      required(path[field.fieldName], { when: () => field.fieldRequired });
      hidden(path[field.fieldName], () => !field.fieldVisible);
      maxLength(path[field.fieldName], () => field.fieldMaxSize);
    }
  });
}

form = form(this.formModel, path => {
  applyWhen(
    path.order,
    context => !!context.valueOf(path.activityType)?.fieldConfig,
    fieldConfigSchema(this.fieldConfig)
  );
});
fieldConfig = computed(() => this.form.activityType().value()?.fieldConfig);
```

Adds `extractValue` utility to the `forms/signals/compat` package. This function extracts the raw value from a `FieldTree`, recursively unwrapping `AbstractControl` instances.

It also allows to filter out only dirty/touched/enabled values or their combination to help reproduce ReactiveForms behavior.

## Key Features
- **Unwraps AbstractControls**: Automatically resolves any `AbstractControl` instances in the `FieldTree` to their underlying values (essential for `compatForm`).
- **Structured Filtering**: Adds `ExtractFilter` to selectively extract fields based on state (`dirty`, `touched`, `enabled`).
- **Array Preservation**: Unlike Reactive Forms which removes filtered array items, `extractValue` preserves index positions by setting filtered items to `undefined`.

## Usage
```ts
const f = compatForm(signal({first: 'Alice', last: new FormControl('Doe')}));
extractValue(f); // {first: 'Alice', last: 'Doe'}

// With filter
extractValue(f, {touched: true});
```

